#!/usr/bin/env python3
"""
Bootstrap: Optical Realization Adapters (Layer 3/4)

Adds three optical realization adapters that convert
FieldInteractionSpec + inverse design output into ranked
fabrication specifications with synthesis protocols.

  PhotonicGlassAdapter  -- Stoeber SiO2 + drop-cast (non-iridescent)
  BraggOpalAdapter      -- vertical deposition opal (iridescent)
  TMMMultilayerAdapter  -- e-beam multilayer stack (directional)

Run from MABE repo root:
  python bootstrap_optical_realization.py
  python -m pytest tests/test_optical/test_optical_realization.py -v
"""

import base64
import pathlib

FILES = {
    'optical/optical_realization.py':
        '',
    'tests/test_optical/test_optical_realization.py':
        '',
}

def main():
    print("Bootstrap: Optical Realization Adapters")
    print("=" * 50)
    print()
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64)
        p.write_bytes(content)
        print(f"  Created: {path} ({len(content):,} bytes)")
    print()
    print("  Run: python -m pytest tests/test_optical/test_optical_realization.py -v")
    print()

if __name__ == "__main__":
    main()